SELECT *
  FROM LOAN_PRODUCT
 WHERE 1=1

    AND provider_id = #{providerId}


    AND product_type_code_value_id = #{productTypeCodeValueId}


    AND loan_type_code_value_id = #{loanTypeCodeValueId}


    AND repayment_type_code_value_id = #{repaymentTypeCodeValueId}

 ORDER BY updated_at DESC, add_date DESC, product_id DESC
